import pytest

# --- The Function Under Test ---
def deep_get(d: dict, keys: str, default=None):
    """Get nested dict value by dot-separated keys."""
    for key in keys.split('.'):
        if isinstance(d, dict):
            d = d.get(key, default)
        else:
            return default
    return d

# --- Unit Tests ---

class TestDeepGet:
    """Tests for the deep_get function."""

    # 1. Happy Path Tests
    class TestHappyPath:
        @pytest.mark.parametrize(
            "input_dict, keys, expected",
            [
                # Single key access
                ({'a': 1}, 'a', 1),
                # Two levels of nesting
                ({'a': {'b': 2}}, 'a.b', 2),
                # Three levels of nesting
                ({'a': {'b': {'c': 3}}}, 'a.b.c', 3),
                # Accessing a nested dict object itself
                ({'a': {'b': 2}}, 'a', {'b': 2}),
                # Accessing a list inside a dict
                ({'a': [1, 2, 3]}, 'a', [1, 2, 3]),
            ]
        )
        def test_retrieval(self, input_dict, keys, expected):
            assert deep_get(input_dict, keys) == expected

        def test_custom_default_ignored_when_found(self):
            """Ensure custom default is not returned if key exists."""
            d = {'a': 1}
            assert deep_get(d, 'a', 'fallback') == 1

    # 2. Edge Case Tests
    class TestEdgeCases:
        def test_missing_key_returns_default(self):
            """Key does not exist in the dictionary."""
            d = {'a': 1}
            assert deep_get(d, 'b') is None
            assert deep_get(d, 'b', 'missing') == 'missing'

        def test_missing_nested_key_returns_default(self):
            """Intermediate key exists, but final key is missing."""
            d = {'a': {'b': 1}}
            # 'a' exists, but 'c' does not
            assert deep_get(d, 'a.c') is None
            assert deep_get(d, 'a.c', 'oops') == 'oops'

        def test_intermediate_value_not_dict(self):
            """Traversal fails because an intermediate value is not a dict."""
            d = {'a': 'string_value'}
            # 'a' is a string, so 'a.b' cannot be traversed
            assert deep_get(d, 'a.b') is None
            assert deep_get(d, 'a.b', 'fallback') == 'fallback'

        def test_initial_d_not_dict(self):
            """The input dictionary 'd' is not actually a dict."""
            # If d is a list, isinstance check fails immediately
            assert deep_get([1, 2, 3], 'a.b') is None
            assert deep_get("string", 'a') is None

        def test_empty_keys_string(self):
            """Keys string is empty. split() returns [''], looking for key ''."""
            d = {'': 'empty_key_value'}
            assert deep_get(d, '') == 'empty_key_value'

            d_no_empty_key = {'a': 1}
            assert deep_get(d_no_empty_key, '') is None

        def test_keys_with_empty_segments(self):
            """Keys string has consecutive dots (e.g., 'a..b')."""
            d = {'a': {'': {'b': 1}}}
            # 'a' -> dict, '' -> dict, 'b' -> 1
            assert deep_get(d, 'a..b') == 1

            d_missing_empty = {'a': {'b': 1}}
            # 'a' -> dict, '' -> missing (returns default)
            assert deep_get(d_missing_empty, 'a..b') is None

